impl Solution { pub fn min_cost(black_s: String, black_cost: Vec<i32>) -> i64 { let (mut black_cnt, mut black_total) = (vec![0i64; 26], 0i64); for (black_i, &black_c) in black_cost.iter().enumerate() { let black_idx = (black_s.as_bytes()[black_i] - b'a') as usize; black_cnt[black_idx] += black_c as i64; black_total += black_c as i64; } black_total - *black_cnt.iter().max().unwrap() } }